#include <stdio.h>
#include <math.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int B, LS;
        scanf("%d %d", &B, &LS);
        double min_RS = sqrt((double)LS * LS - (double)B * B);
        double max_RS = sqrt((double)LS * LS + (double)B * B);
        printf("%.5f %.5f\n", min_RS, max_RS);
    }
    return 0;
}

