code.Java:
import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            st = new StringTokenizer(br.readLine());
            int B = Integer.parseInt(st.nextToken());
            int LS = Integer.parseInt(st.nextToken());
            double minRS = Math.sqrt((double) LS * LS - (double) B * B);
            double maxRS = Math.sqrt((double) LS * LS + (double) B * B);
            sb.append(String.format(java.util.Locale.US, "%.5f %.5f", minRS, maxRS));
            if (i + 1 < T) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

